// No-op stub for tas-client (Treatment Assignment Service).
// This project does not use Microsoft's experimentation service.
// All experiment flags return default values (false/undefined).
// See: https://github.com/j4rviscmd/vscodeee/issues/296

"use strict";

/**
 * No-op ExperimentationService.
 * Mirrors the real tas-client API surface but never contacts any server.
 */
class ExperimentationService {
	constructor(_config) {
		this.initializePromise = Promise.resolve();
		this.initialFetch = Promise.resolve();
	}

	isFlightEnabled(_flight) {
		return false;
	}

	isCachedFlightEnabled(_flight) {
		return Promise.resolve(false);
	}

	isFlightEnabledAsync(_flight) {
		return Promise.resolve(false);
	}

	getTreatmentVariable(_configId, _name) {
		return undefined;
	}

	getTreatmentVariableAsync(_configId, _name, _checkCache) {
		return Promise.resolve(undefined);
	}
}

module.exports.ExperimentationService = ExperimentationService;

// Also export as named for `import { ExperimentationService } from 'tas-client'`
module.exports.ExperimentationServiceConfig = {};
